449	/** EDT-02 — anchor point on a referenced element used by the evaluator. */
450	export type ConstraintAnchor = 'start' | 'end' | 'mid' | 'center';
451	
452	export type ConstraintSeverity = 'warning' | 'error';
453	
454	export type ConstraintRefRow = {
