```python
@api_router.get("/v3/models/{model_id}/schedules/{schedule_id}/rows")
async def schedule_view_rows(
    model_id: UUID,
    schedule_id: str,
    session: AsyncSession = Depends(get_session),
    filter_expr: Annotated[str | None, Query(alias="filterExpr")] = None,
    sort_key: Annotated[str | None, Query(alias="sortKey")] = None,
    sort_dir: Annotated[str | None, Query(alias="sortDir")] = None,
) -> list[dict]:
    row = await load_model_row(session, model_id)
    if row is None:
        raise HTTPException(status_code=404, detail="Model not found")
    doc = Document.model_validate(row.document)

    from bim_ai.elements import ScheduleElem
    sv = doc.elements.get(schedule_id)
    if not isinstance(sv, ScheduleElem):
        raise HTTPException(status_code=404, detail="Schedule view not found")

    category = sv.category
    if not category:
        raise HTTPException(status_code=400, detail="Schedule has no category set")

    effective_filter = filter_expr if filter_expr is not None else sv.filter_expr
    effective_sort_key = sort_key if sort_key is not None else sv.sort_key
    effective_sort_dir = sort_dir if sort_dir is not None else sv.sort_dir

    # Collect rows for matching category
    rows = []
    for elem_id, elem in doc.elements.items():
        if getattr(elem, "kind", None) != category:
            continue

        # Build fields dict from element attributes
        fields: dict[str, Any] = {"id": elem_id}
        # Common built-in fields
        for attr in ("name", "length_mm", "width_mm", "height_mm", "thickness_mm", "area_m2"):
            val = getattr(elem, attr, None)
            if val is not None:
                # Convert snake_case to camelCase for the wire
                camel = attr[0] + "".join(w.capitalize() for w in attr.split("_")[1:])
                fields[camel] = val
        # Special derived fields
        if category == "wall":
            start = getattr(elem, "start", None)
            end = getattr(elem, "end", None)
            if start and end:
                import math
                dx = end.x_mm - start.x_mm
                dy = end.y_mm - start.y_mm
                fields["lengthMm"] = round(math.sqrt(dx*dx + dy*dy), 1)
            thickness = getattr(elem, "thickness_mm", None)
            if thickness is not None:
                fields["thicknessMm"] = thickness
            height = getattr(elem, "height_mm", None)
            if height is not None:
                fields["heightMm"] = height
        # Custom props
        props = getattr(elem, "props", None)
        if props:
            fields.update(props)

        # Apply filterExpr (simple string match on any field value)
        if effective_filter:
            filter_lower = effective_filter.lower()
            match_found = any(filter_lower in str(v).lower() for v in fields.values())
            if not match_found:
                continue

        rows.append({"elementId": elem_id, "fields": fields})

    # Sort
    if effective_sort_key:
        reverse = (effective_sort_dir == "desc")
        rows.sort(
            key=lambda r: (r["fields"].get(effective_sort_key) is None, r["fields"].get(effective_sort_key, "")),
            reverse=reverse,
        )

    return rows
```

