/**
 * SCH-V3-01 — Filterable schedule view component.
 *
 * Fetches rows from GET /api/v3/models/{modelId}/schedules/{scheduleId}/rows,
 * supports client-side filter-box (debounced 300 ms), sortable sticky header,
 * row hover highlight, and inline cell editing (Enter / Escape / blur commit).
 *
 * All colours use CSS custom properties — no hex literals.
 */
import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface ScheduleRow {
  elementId: string;
  fields: Record<string, unknown>;
}

interface ColumnDef {
  key: string;
  label?: string;
}

interface ScheduleViewProps {
  modelId: string;
  scheduleId: string;
  columns?: ColumnDef[];
  /** Called after a cell edit is committed to let the parent refresh state. */
  onPropSet?: (elementId: string, key: string, value: unknown) => void;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function useDebounce<T>(value: T, delayMs: number): T {
  const [debounced, setDebounced] = useState<T>(value);
  useEffect(() => {
    const t = setTimeout(() => setDebounced(value), delayMs);
    return () => clearTimeout(t);
  }, [value, delayMs]);
  return debounced;
}

function formatCellValue(v: unknown): string {
  if (v === null || v === undefined) return '';
  if (typeof v === 'boolean') return v ? 'Yes' : 'No';
  return String(v);
}

// ---------------------------------------------------------------------------
// Inline-editable cell
// ---------------------------------------------------------------------------

interface EditableCellProps {
  value: unknown;
  onCommit: (newVal: string) => void;
}

function EditableCell({ value, onCommit }: EditableCellProps) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  const startEdit = () => {
    setDraft(formatCellValue(value));
    setEditing(true);
  };

  useEffect(() => {
    if (editing) inputRef.current?.focus();
  }, [editing]);

  const commit = () => {
    setEditing(false);
    onCommit(draft);
  };

  const discard = () => setEditing(false);

  if (editing) {
    return (
      <input
        ref={inputRef}
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === 'Enter') commit();
          if (e.key === 'Escape') discard();
        }}
        onBlur={commit}
        style={{
          width: '100%',
          border: 'none',
          outline: '2px solid var(--color-accent, #0070f3)',
          background: 'var(--color-surface, #fff)',
          color: 'var(--color-text, #000)',
          padding: '2px 4px',
          fontSize: 'inherit',
          fontFamily: 'inherit',
        }}
      />
    );
  }

  return (
    <span
      title="Double-click to edit"
      onDoubleClick={startEdit}
      style={{ display: 'block', minHeight: '1.2em', cursor: 'text' }}
    >
      {formatCellValue(value)}
    </span>
  );
}

// ---------------------------------------------------------------------------
// Main component
// ---------------------------------------------------------------------------

export function ScheduleView({
  modelId,
  scheduleId,
  columns: columnsProp,
  onPropSet,
}: ScheduleViewProps) {
  const [rows, setRows] = useState<ScheduleRow[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [filterText, setFilterText] = useState('');
  const [sortKey, setSortKey] = useState<string | null>(null);
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc');
  const [hoveredId, setHoveredId] = useState<string | null>(null);

  const debouncedFilter = useDebounce(filterText, 300);

  const fetchRows = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const params = new URLSearchParams();
      if (debouncedFilter) params.set('filterExpr', debouncedFilter);
      if (sortKey) params.set('sortKey', sortKey);
      if (sortKey) params.set('sortDir', sortDir);
      const url = `/api/v3/models/${modelId}/schedules/${scheduleId}/rows${params.toString() ? '?' + params.toString() : ''}`;
      const res = await fetch(url);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      setRows(await res.json());
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Unknown error');
    } finally {
      setLoading(false);
    }
  }, [modelId, scheduleId, debouncedFilter, sortKey, sortDir]);

  useEffect(() => {
    void fetchRows();
  }, [fetchRows]);

  // Derive columns from prop or from the first row
  const columns = useMemo<ColumnDef[]>(() => {
    if (columnsProp && columnsProp.length > 0) return columnsProp;
    if (rows.length === 0) return [];
    return Object.keys(rows[0].fields).map((k) => ({ key: k, label: k }));
  }, [columnsProp, rows]);

  const handleSort = (key: string) => {
    if (sortKey === key) {
      setSortDir((d) => (d === 'asc' ? 'desc' : 'asc'));
    } else {
      setSortKey(key);
      setSortDir('asc');
    }
  };

  const handleCommit = async (row: ScheduleRow, key: string, newVal: string) => {
    try {
      await fetch(`/api/v3/models/${modelId}/bundles`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          commands: [
            {
              type: 'set_element_prop',
              elementId: row.elementId,
              key,
              value: newVal,
            },
          ],
        }),
      });
      onPropSet?.(row.elementId, key, newVal);
      await fetchRows();
    } catch {
      // silently ignore — the cell will revert on next fetch
    }
  };

  return (
    <div
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        fontFamily: 'var(--font-sans, sans-serif)',
        fontSize: '13px',
        color: 'var(--color-text, #000)',
        background: 'var(--color-surface, #fff)',
      }}
    >
      {/* Filter bar */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: '8px',
          padding: '8px 12px',
          borderBottom: '1px solid var(--color-border, #e5e7eb)',
          background: 'var(--color-surface-raised, #f9fafb)',
        }}
      >
        <input
          type="search"
          placeholder="Filter…"
          value={filterText}
          onChange={(e) => setFilterText(e.target.value)}
          style={{
            flex: 1,
            padding: '4px 8px',
            border: '1px solid var(--color-border, #e5e7eb)',
            borderRadius: '4px',
            background: 'var(--color-surface, #fff)',
            color: 'var(--color-text, #000)',
            fontSize: 'inherit',
            outline: 'none',
          }}
        />
        {loading && <span style={{ color: 'var(--color-text-muted, #6b7280)' }}>Loading…</span>}
      </div>

      {/* Error state */}
      {error && (
        <div
          style={{
            padding: '8px 12px',
            color: 'var(--color-error, #dc2626)',
            background: 'var(--color-error-bg, #fef2f2)',
          }}
        >
          {error}
        </div>
      )}

      {/* Table */}
      <div style={{ flex: 1, overflow: 'auto' }}>
        <table
          style={{
            width: '100%',
            borderCollapse: 'collapse',
            tableLayout: 'fixed',
          }}
        >
          <thead
            style={{
              position: 'sticky',
              top: 0,
              background: 'var(--color-surface-raised, #f9fafb)',
              zIndex: 1,
            }}
          >
            <tr>
              {columns.map((col) => (
                <th
                  key={col.key}
                  onClick={() => handleSort(col.key)}
                  style={{
                    padding: '6px 10px',
                    textAlign: 'left',
                    borderBottom: '2px solid var(--color-border, #e5e7eb)',
                    cursor: 'pointer',
                    userSelect: 'none',
                    whiteSpace: 'nowrap',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    fontWeight: 600,
                    color:
                      sortKey === col.key
                        ? 'var(--color-accent, #0070f3)'
                        : 'var(--color-text, #000)',
                  }}
                >
                  {col.label ?? col.key}
                  {sortKey === col.key ? (sortDir === 'asc' ? ' ↑' : ' ↓') : ''}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {rows.length === 0 && !loading && (
              <tr>
                <td
                  colSpan={columns.length || 1}
                  style={{
                    padding: '16px',
                    textAlign: 'center',
                    color: 'var(--color-text-muted, #6b7280)',
                  }}
                >
                  No rows
                </td>
              </tr>
            )}
            {rows.map((row) => (
              <tr
                key={row.elementId}
                onMouseEnter={() => setHoveredId(row.elementId)}
                onMouseLeave={() => setHoveredId(null)}
                style={{
                  background:
                    hoveredId === row.elementId
                      ? 'var(--color-surface-hovered, #f0f4ff)'
                      : 'transparent',
                  transition: 'background 80ms',
                }}
              >
                {columns.map((col) => (
                  <td
                    key={col.key}
                    style={{
                      padding: '5px 10px',
                      borderBottom: '1px solid var(--color-border-subtle, #f3f4f6)',
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                    }}
                  >
                    <EditableCell
                      value={row.fields[col.key]}
                      onCommit={(v) => handleCommit(row, col.key, v)}
                    />
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Footer */}
      <div
        style={{
          padding: '4px 12px',
          borderTop: '1px solid var(--color-border, #e5e7eb)',
          color: 'var(--color-text-muted, #6b7280)',
          background: 'var(--color-surface-raised, #f9fafb)',
          fontSize: '11px',
        }}
      >
        {rows.length} row{rows.length !== 1 ? 's' : ''}
      </div>
    </div>
  );
}

export default ScheduleView;

